import{_ as e,o as s,c as i,a2 as n}from"./chunks/framework.LN3EJxkW.js";const k=JSON.parse('{"title":"在线回填、零停机发布与可执行回滚","description":"","frontmatter":{},"headers":[],"relativePath":"05-backend-data/notes/06-api-database/20-zero-downtime-backfill-rollback.md","filePath":"05-backend-data/notes/06-api-database/20-zero-downtime-backfill-rollback.md","lastUpdated":null}'),l={name:"05-backend-data/notes/06-api-database/20-zero-downtime-backfill-rollback.md"};function t(r,a,p,o,h,c){return s(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="在线回填、零停机发布与可执行回滚" tabindex="-1">在线回填、零停机发布与可执行回滚 <a class="header-anchor" href="#在线回填、零停机发布与可执行回滚" aria-label="Permalink to &quot;在线回填、零停机发布与可执行回滚&quot;">​</a></h1><p>“零停机”不是没有风险或没有延迟，而是在迁移期间持续满足明确的服务目标：旧/新版本共存、请求正确、延迟和错误率在预算内、数据可验证、异常时能暂停或回退。</p><h2 id="_1-定义发布不变量" tabindex="-1">1. 定义发布不变量 <a class="header-anchor" href="#_1-定义发布不变量" aria-label="Permalink to &quot;1. 定义发布不变量&quot;">​</a></h2><p>迁移前写出可测条件：</p><ul><li>旧版与新版应用都能读写 expand 后 schema。</li><li>新写入不会遗漏目标列。</li><li>历史回填不覆盖用户更新。</li><li>主库 p95、锁等待、复制延迟、WAL 和磁盘不超过停止阈值。</li><li>回填可暂停、续跑和重复执行。</li><li>读切换可在分钟级回退，contract 前不删除回退所需数据。</li></ul><p>这些条件比“脚本执行成功”更接近完成。</p><h2 id="_2-在线回填的数据竞态" tabindex="-1">2. 在线回填的数据竞态 <a class="header-anchor" href="#_2-在线回填的数据竞态" aria-label="Permalink to &quot;2. 在线回填的数据竞态&quot;">​</a></h2><p>简单脚本“扫描旧列→计算→更新新列”会与在线写入竞争。若用户在扫描和 UPDATE 之间修改，回填可能把新值覆盖为旧派生值。</p><p>使用条件更新保护：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">UPDATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> accounts</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> normalized_email </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> lower</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(email),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    normalization_version </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> account_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> account_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> normalized_email </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">IS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> NULL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>若计算必须基于读到的旧版本，带版本条件：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>UPDATE accounts</span></span>
<span class="line"><span>SET target = $computed, migration_version = 2</span></span>
<span class="line"><span>WHERE account_id = $id</span></span>
<span class="line"><span>  AND source_version = $observed_version</span></span>
<span class="line"><span>  AND target IS NULL;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>零影响行表示在线更新或其他 worker 竞争，重新读取而不是覆盖。</p><h2 id="_3-稳定分批与-checkpoint" tabindex="-1">3. 稳定分批与 checkpoint <a class="header-anchor" href="#_3-稳定分批与-checkpoint" aria-label="Permalink to &quot;3. 稳定分批与 checkpoint&quot;">​</a></h2><p>选择不可变或单调主键 keyset，不用不断变大的 OFFSET：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SELECT account_id</span></span>
<span class="line"><span>FROM accounts</span></span>
<span class="line"><span>WHERE account_id &gt; $last</span></span>
<span class="line"><span>  AND target IS NULL</span></span>
<span class="line"><span>ORDER BY account_id</span></span>
<span class="line"><span>LIMIT 1000;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>UUID 无自然顺序也可按 <code>(created_at, id)</code> 或哈希分片处理，但游标和边界必须稳定。多个 worker 可预分配不重叠范围，或用任务表/<code>SKIP LOCKED</code> 领取；不能各自从头扫造成放大。</p><p>checkpoint 记录 job/version、range、last key、处理/跳过/错误数、开始结束时间。提交数据批次后再更新 checkpoint，或让二者在同一事务；即使 checkpoint 落后，幂等条件允许安全重跑。</p><h2 id="_4-批大小与节流" tabindex="-1">4. 批大小与节流 <a class="header-anchor" href="#_4-批大小与节流" aria-label="Permalink to &quot;4. 批大小与节流&quot;">​</a></h2><p>批越大吞吐高但事务、锁、WAL 峰值和回滚时间更大。采用反馈控制而非固定全速：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if replica_lag &gt; 10s or db_cpu &gt; 75% or lock_wait_p95 &gt; 100ms:</span></span>
<span class="line"><span>    pause or reduce batch/rate</span></span>
<span class="line"><span>else if system has headroom:</span></span>
<span class="line"><span>    slowly increase rate</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>停止阈值按实际 SLO 定义。监控：rows/s、batch duration、dead tuples、WAL bytes/s、replication lag、checkpoint I/O、autovacuum、锁等待、应用 p95/p99、错误率和 pool wait。</p><p>回填 UPDATE 会创建新行版本并增加 WAL/表膨胀。即使每批很短，总量仍可能触发存储和复制压力；演练必须接近生产数据规模和分布。</p><h2 id="_5-双写策略" tabindex="-1">5. 双写策略 <a class="header-anchor" href="#_5-双写策略" aria-label="Permalink to &quot;5. 双写策略&quot;">​</a></h2><h3 id="应用双写" tabindex="-1">应用双写 <a class="header-anchor" href="#应用双写" aria-label="Permalink to &quot;应用双写&quot;">​</a></h3><p>优点：逻辑可见、容易逐步发布；缺点：所有写入口必须升级，包括后台任务、管理脚本、导入和旧客户端。两列应在同一事务写，不能先写旧列后异步写新列而无对账。</p><h3 id="数据库-trigger" tabindex="-1">数据库 trigger <a class="header-anchor" href="#数据库-trigger" aria-label="Permalink to &quot;数据库 trigger&quot;">​</a></h3><p>优点：覆盖所有数据库写入者；缺点：隐藏逻辑、额外写成本、递归/顺序与移除风险。触发器函数要版本化、测试 bulk load 和复制行为。</p><h3 id="change-data-capture" tabindex="-1">Change Data Capture <a class="header-anchor" href="#change-data-capture" aria-label="Permalink to &quot;Change Data Capture&quot;">​</a></h3><p>适合跨存储迁移，但通常异步并有延迟/重复/乱序。需要事件位置、幂等、删除语义、schema 演进和全量+增量切换水位。不能宣称瞬时一致。</p><h2 id="_6-影子读与差异验证" tabindex="-1">6. 影子读与差异验证 <a class="header-anchor" href="#_6-影子读与差异验证" aria-label="Permalink to &quot;6. 影子读与差异验证&quot;">​</a></h2><p>新读路径先不影响用户结果，后台读取新模型并与旧结果比较。影子请求必须有资源预算，不能把生产流量翻倍压垮数据库。</p><p>差异分类：等价格式差异、已知舍入、真实数据遗漏、顺序不稳定、权限差异。指标 label 不放资源 ID；详细差异进入受限抽样日志，脱敏并设保留期。</p><p>验证方法组合：</p><ul><li>精确计数：<code>target IS NULL</code>、非法状态、孤儿外键。</li><li>聚合对账：按 tenant/day 的 count/sum。</li><li>哈希：按稳定排序和规范化格式做分片 hash。</li><li>随机与风险抽样：大租户、边界金额、多语言字符。</li><li>业务不变量：总额守恒、状态迁移合法、跨租户为零。</li></ul><p>只比较总行数会漏掉“一行丢、一行重复”。</p><h2 id="_7-canary-与读切换" tabindex="-1">7. Canary 与读切换 <a class="header-anchor" href="#_7-canary-与读切换" aria-label="Permalink to &quot;7. Canary 与读切换&quot;">​</a></h2><p>切换层次可为：内部用户→1%租户→10%→50%→100%。租户级切换比请求随机切换更易保持一致缓存和排障。每阶段比较错误、延迟、差异、数据库负载和工单。</p><p>feature flag 本身要有审计、默认值和依赖失效策略。若配置服务不可用，明确保持上次值或回到安全旧路径；不能随机变化。</p><p>缓存 key/version 必须区分新旧表示，切读时清理或自然过期。异步任务也可能在数小时后运行旧代码/旧 payload，不能只看在线副本已升级。</p><h2 id="_8-回滚的层级" tabindex="-1">8. 回滚的层级 <a class="header-anchor" href="#_8-回滚的层级" aria-label="Permalink to &quot;8. 回滚的层级&quot;">​</a></h2><h3 id="_8-1-暂停" tabindex="-1">8.1 暂停 <a class="header-anchor" href="#_8-1-暂停" aria-label="Permalink to &quot;8.1 暂停&quot;">​</a></h3><p>第一动作往往是暂停回填/扩容，保留已处理数据，降低负载。脚本必须响应取消并在当前小批提交后安全退出。</p><h3 id="_8-2-流量回退" tabindex="-1">8.2 流量回退 <a class="header-anchor" href="#_8-2-流量回退" aria-label="Permalink to &quot;8.2 流量回退&quot;">​</a></h3><p>feature flag 切回旧读。前提是双写仍保持旧结构可用，新数据能由旧模型表达。切回后继续监控，不能立即执行 destructive down migration。</p><h3 id="_8-3-应用版本回退" tabindex="-1">8.3 应用版本回退 <a class="header-anchor" href="#_8-3-应用版本回退" aria-label="Permalink to &quot;8.3 应用版本回退&quot;">​</a></h3><p>旧二进制必须兼容 expand schema 和新写入。若新应用已经产生旧版无法理解的枚举/状态，回退会失败；应先禁用新功能、迁移/隔离这些数据。</p><h3 id="_8-4-数据修复-恢复" tabindex="-1">8.4 数据修复/恢复 <a class="header-anchor" href="#_8-4-数据修复-恢复" aria-label="Permalink to &quot;8.4 数据修复/恢复&quot;">​</a></h3><p>错误回填可用记录的 job ID/version 选择性修复。如果旧值未保留且变换不可逆，只能从备份/PITR 恢复到旁路实例，再提取受影响数据；这不是快速 <code>down.sql</code>。</p><p>回滚脚本本身也要先演练、分批、带条件和审计。</p><h2 id="_9-部署顺序示例" tabindex="-1">9. 部署顺序示例 <a class="header-anchor" href="#_9-部署顺序示例" aria-label="Permalink to &quot;9. 部署顺序示例&quot;">​</a></h2><p>目标将 <code>orders.customer_email</code> 转为 <code>customer_contact_id</code>：</p><ol><li>Expand 新 contact 表和可空 FK 列，旧应用不受影响。</li><li>部署双写版本：创建/更新订单时在同一事务 upsert contact 并写 ID，同时保留 email。</li><li>运行限速回填，按 order ID 分批，条件为 contact_id IS NULL。</li><li>验证每租户 count、孤儿、email 映射和跨租户不变量。</li><li>影子读 contact，与旧 email 比较。</li><li>canary 切新读；逐步扩大。</li><li>停止旧写，观察旧列变化归零。</li><li>添加并验证 FK/NOT NULL。</li><li>经过回退窗口后在独立发布 contract 删除旧列。</li></ol><h2 id="_10-完整案例-一亿行邮箱规范化" tabindex="-1">10. 完整案例：一亿行邮箱规范化 <a class="header-anchor" href="#_10-完整案例-一亿行邮箱规范化" aria-label="Permalink to &quot;10. 完整案例：一亿行邮箱规范化&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p><code>accounts</code> 一亿行，需要新增 <code>email_lookup_key</code> 用于精确匹配。业务仍在线；用户可能修改邮箱；读副本延迟 SLO &lt; 10 s；主库 p95 增幅不得超过 10%。</p><h3 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h3><ol><li>定义规范化算法版本和 Unicode/域名规则；新增可空 lookup key 与 version。</li><li>应用写路径在同一事务按原始 email 计算 key；唯一约束范围包含 tenant，并先处理历史冲突。</li><li>回填 worker 按主键 keyset 每批 500，<code>WHERE key IS NULL</code> 条件更新，记录 checkpoint。</li><li>控制器每批读取 replica lag、DB CPU、lock wait 和应用 p95；超阈值暂停 60 秒并降低速率。</li><li>每百万行做 tenant 分组计数和重复 key 验证；完成后全量 NULL=0。</li><li>新查询先影子运行，差异分类；canary 按租户切读。</li><li>观察旧路径 14 天后再验证/收紧约束，暂不删除原始 email（它仍是展示数据）。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>回填可中断续跑，用户在线修改不被覆盖；查询逐步切换，数据库和复制指标保持阈值内。算法版本让未来规则更新可再迁移。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>随机杀死 worker，重启从 checkpoint 继续且无错误覆盖。</li><li>人工制造 replica lag，节流器暂停。</li><li>回填与用户修改同一行并发，最终 key 对应最新 email。</li><li>影子读在大小租户和国际化邮箱样本中无未知差异。</li><li>关闭新读 flag 后旧路径立即恢复且新写仍双写。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若回填先 SELECT email、长时间计算、再无条件 UPDATE，用户在间隔修改会得到旧 key。修正为在单条条件 UPDATE 中计算，或比较源版本。若新版本立刻停止旧写，应用回退后新订单缺旧字段；应保持双写直到回退窗口结束。</p><h2 id="_11-故障演练" tabindex="-1">11. 故障演练 <a class="header-anchor" href="#_11-故障演练" aria-label="Permalink to &quot;11. 故障演练&quot;">​</a></h2><p>演练至少包括：DDL lock timeout；回填进程崩溃；重复启动两个 worker；主库 failover；复制延迟；磁盘接近阈值；feature flag 服务故障；新旧读结果不一致；回滚时存在新版状态。</p><p>每次演练记录检测信号、停止动作、数据状态、恢复步骤和耗时。没有实际演练的 runbook 只是文档假设。</p><h2 id="_12-常见错误与练习" tabindex="-1">12. 常见错误与练习 <a class="header-anchor" href="#_12-常见错误与练习" aria-label="Permalink to &quot;12. 常见错误与练习&quot;">​</a></h2><p>错误包括：单次 UPDATE 全表；OFFSET 分页；回填无条件覆盖；只监控 worker rows/s；完成后立即 drop 旧列；down migration 直接逆转不可逆数据；影子流量无预算；contract 前未检查后台任务和旧客户端。</p><p>练习：设计 5000 万订单的货币单位迁移，从 decimal 元到 bigint 分，包含舍入、异常数据、双写、回填、对账、canary 和回滚。</p><p>完成标准：规则版本化；每批短事务且 keyset；并发更新不覆盖；节流阈值明确；sum/count/异常对账；旧新应用共存；流量回退分钟级；不可逆数据有旁路恢复方案；contract 独立审批。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.postgresql.org/docs/18/sql-altertable.html" target="_blank" rel="noreferrer">PostgreSQL 18: ALTER TABLE</a>（访问日期：2026-07-17）</li><li><a href="https://www.postgresql.org/docs/18/sql-createindex.html" target="_blank" rel="noreferrer">PostgreSQL 18: CREATE INDEX</a>（访问日期：2026-07-17）</li><li><a href="https://www.postgresql.org/docs/18/monitoring-stats.html" target="_blank" rel="noreferrer">PostgreSQL 18: Monitoring Database Activity</a>（访问日期：2026-07-17）</li><li><a href="https://www.postgresql.org/docs/18/routine-vacuuming.html" target="_blank" rel="noreferrer">PostgreSQL 18: Routine Vacuuming</a>（访问日期：2026-07-17）</li><li><a href="https://www.postgresql.org/docs/release/18.4/" target="_blank" rel="noreferrer">PostgreSQL 18.4 Release Notes</a>（访问日期：2026-07-17）</li></ul>`,73)])])}const u=e(l,[["render",t]]);export{k as __pageData,u as default};
